(function(){
  "use strict";
  var TWO_PI=Math.PI*2, DEG=Math.PI/180;
  var reduce=window.matchMedia("(prefers-reduced-motion:reduce)").matches;
  var canvas=document.getElementById("c"), ctx=canvas.getContext("2d");
  var introEl=document.getElementById("intro");
  var quizEl=document.getElementById("quiz");
  var paraEl=document.getElementById("para"), hintEl=document.getElementById("hint"), eyebrow=document.getElementById("eyebrow");
  var track=document.querySelector(".hero-track");
  function shuffle(a){for(var i=a.length-1;i>0;i--){var j=(Math.random()*(i+1))|0,t=a[i];a[i]=a[j];a[j]=t;}return a;}
  function clamp(v,a,b){return v<a?a:v>b?b:v;}
  function remap(v,a,b){return clamp((v-a)/(b-a),0,1);}
  function easeInOut(t){return t<0.5?4*t*t*t:1-Math.pow(-2*t+2,3)/2;}
  function lerp(a,b,t){return a+(b-a)*t;}

  var raw=paraEl.textContent; paraEl.textContent=""; var chars=[];
  for(var i=0;i<raw.length;i++){var s=document.createElement("span");s.className="ch";s.textContent=raw[i];paraEl.appendChild(s);chars.push(s);}

  var LON_MIN=-180, LON_STEP=1.25, NLON=288, LAT_MAX=84, LAT_STEP=1.25, NLAT=135;
  var LANDMASK="";
  var globe=[];
  for(var r=0;r<NLAT;r++){ var lat=LAT_MAX-r*LAT_STEP;
    for(var col=0;col<NLON;col++){
      if(LANDMASK.charCodeAt(r*NLON+col)===48) continue;
      var lon=LON_MIN+col*LON_STEP, la=lat*DEG, lo=lon*DEG;
      globe.push({x:Math.cos(la)*Math.sin(lo), y:Math.sin(la), z:Math.cos(la)*Math.cos(lo)});
    } }
  shuffle(globe);

  // Marcadores tipo "mapa de estadísticas": puntos amarillos que laten (escala) en varios países.
  var MARKERS=[];
  (function(){
    // [lat, lon, factor de tamaño opcional]
    var pts=[[40.4,-3.7],[9,8,1.9],[21,78],[-10,-52,1.9],[23,-102],[15,100],[45,25],[39,-98],[1,38],[12,122],[4,-73,1.9]];
    for(var mi=0;mi<pts.length;mi++){
      var mla=pts[mi][0]*DEG, mlo=pts[mi][1]*DEG, big=pts[mi][2]||1;
      MARKERS.push({ x:Math.cos(mla)*Math.sin(mlo), y:Math.sin(mla), z:Math.cos(mla)*Math.cos(mlo),
        phase:Math.random()*TWO_PI, speed:1.5+Math.random()*1.3, size:(0.019+Math.random()*0.011)*big });
    }
  })();

  var COLS=8, ROWS=6, FRAMES=48, FW=640, FH=540;
  var sprite=new Image(), spriteReady=false, cellsReady=false, cells=[], P=[], N=0;
  // Vídeo 2 (lo que reconstruyen los fragmentos). PLACEHOLDER: el mismo sprite actual.
  // Para el clip definitivo: pon V2.src con su sprite-sheet y ajusta cols/rows/frames/fw/fh/frame.
  var V2={ src:"data:image/webp;base64,", cols:6, rows:5, frames:26, fw:720, fh:720, frame:0 };
  var sprite2=new Image(), sprite2Ready=false, cells2=[];
  var GW=140, GH=118;
  sprite.onload=function(){ spriteReady=true; if(!sprite2.src){ sprite2.src=V2.src||sprite.src; } tryBuild(); };
  sprite2.onload=function(){ sprite2Ready=true; tryBuild(); };
  sprite.src="data:image/jpeg;base64,";

  function sampleFrame(img, frameIdx, cols, fw, fh){
    var off=document.createElement("canvas"); off.width=GW; off.height=GH;
    var o=off.getContext("2d");
    var col=frameIdx%cols, row=(frameIdx/cols)|0;
    o.drawImage(img, col*fw,row*fh,fw,fh, 0,0,GW,GH);
    var d=o.getImageData(0,0,GW,GH).data, arr=[];
    for(var y=0;y<GH;y++){ for(var x=0;x<GW;x++){
      var k=(y*GW+x)*4, rr=d[k],gg=d[k+1],bb=d[k+2];
      if((255-rr)+(255-gg)+(255-bb) < 60) continue;
      arr.push({ u:x/GW-0.5, v:y/GH-0.5, r:rr, g:gg, b:bb });
    } }
    shuffle(arr);
    return arr;
  }

  function tryBuild(){
    if(!spriteReady || !sprite2Ready || !globe.length) return;
    cells  = sampleFrame(sprite,  FRAMES-1, COLS,    FW,    FH);     // vídeo 1 (origen): último fotograma
    cells2 = sampleFrame(sprite2, V2.frame, V2.cols, V2.fw, V2.fh);  // vídeo 2 (destino): fotograma elegido
    N=Math.min(globe.length, cells.length, cells2.length);
    P=new Array(N);
    for(var i=0;i<N;i++){
      var c=cells[i];
      var proj=c.u*0.96 + c.v*0.28;
      var posDelay=clamp((0.62-proj)/1.24,0,1);
      var delay=clamp(0.7*posDelay + 0.3*Math.random(),0,1)*0.6;
      P[i]={ cell:c, glb:globe[i], cell2:cells2[i],
        delay:delay,
        wind:0.45+Math.random()*1.15,
        lat:(Math.random()*2-1),
        swayA:0.5+Math.random()*1.1,
        swayF:1.0+Math.random()*2.2,
        phase:Math.random()*TWO_PI,
        bob:Math.random() };
    }
    cellsReady=true;
  }

  var W=0,H=0,dpr=1,cx=0,cy=0,R=0,imgCx=0,imgCy=0,imgW=0,imgH=0,imgPitch=0,img2Cx=0,img2Cy=0,img2W=0,img2H=0,img2Pitch=0;
  function resize(){
    dpr=Math.min(window.devicePixelRatio||1,2);
    W=canvas.clientWidth; H=canvas.clientHeight;
    canvas.width=W*dpr; canvas.height=H*dpr; ctx.setTransform(dpr,0,0,dpr,0,0);
    var mobile=W<760;
    cx=mobile?W*0.5:W*0.70; cy=mobile?H*0.42:H*0.5;
    R=Math.min(W,H)*(mobile?0.30:0.33);
    // colocación del vídeo 2 reconstruido (móvil: a sangre completa; desktop: columna izquierda)
    img2W=mobile?(W*1.25):(H*(V2.fw/V2.fh));      // móvil: sangra por los lados (sin espacio lateral)
    img2H=mobile?(img2W*(V2.fh/V2.fw)):H;
    img2Cx=mobile?W*0.5:W*0.30;
    img2Cy=mobile?(img2H*0.5):H*0.5;              // móvil: pegado arriba (sin espacio superior)
    img2Pitch=img2W/GW;
    imgH=mobile?(W*(FH/FW)):H;              // móvil: ancho completo; desktop: alto completo
    imgW=imgH*(FW/FH);
    imgCx=mobile?(W*0.5):(W - imgW*0.4375); // móvil: centrada a sangre; desktop: pegada a la derecha
    imgCy=imgH*0.5;
    imgPitch=imgW/GW;
  }
  window.addEventListener("resize",resize); resize();

  var p=0;
  // La animación termina al 80% del track; el último 20% queda en estado final (estático)
  // mientras la sección del formulario sube por encima (efecto cover).
  function onScroll(){var rect=track.getBoundingClientRect();var total=track.offsetHeight-window.innerHeight;p=clamp((-rect.top/total)/0.80,0,1);}
  window.addEventListener("scroll",onScroll,{passive:true}); onScroll();

  var TURNS=1.6;
  function frame(){
    var pp=reduce?1:p;
    // ---- línea de tiempo ----
    var m1=remap(pp,0.26,0.52);                 // diente de león 1: persona → globo 1 (derecha)
    // rotación continua: el globo nunca se detiene en seco (formación suave + giro lento sostenido)
    var angle1=TWO_PI*(TURNS*easeInOut(remap(pp,0.22,0.60)) + 0.8*pp);
    var reveal=remap(pp,0.50,0.60);
    var m2=remap(pp,0.64,0.84);                 // diente de león 2: globo 1 → vídeo 2 (se ensambla antes)
    var scene2=pp>=0.64;

    // ---- texto ----
    var lit=Math.floor(reveal*chars.length);
    for(var i=0;i<chars.length;i++){var on=i<lit; if(on!==chars[i]._on){chars[i]._on=on;chars[i].classList.toggle("lit",on);}}
    eyebrow.classList.toggle("show", pp>0.46 && pp<0.62);
    if(hintEl) hintEl.style.opacity = pp>0.04?0:1;
    paraEl.style.opacity = remap(pp,0.44,0.52) * (1 - remap(pp,0.58,0.64));
    if(introEl) introEl.style.opacity = 1 - remap(pp,0.18,0.26);
    if(quizEl){ var qo=remap(pp,0.84,0.94); quizEl.style.opacity=qo; quizEl.style.pointerEvents=qo>0.5?"auto":"none"; }

    ctx.clearRect(0,0,W,H);

    // ---- persona (fotogramas) ----
    if(spriteReady && pp<0.30){
      var fa=1-remap(pp,0.26,0.30);
      if(fa>0){
        var fi=clamp(Math.round(remap(pp,0,0.28)*(FRAMES-1)),0,FRAMES-1);
        var fcol=fi%COLS, frow=(fi/COLS)|0;
        ctx.globalAlpha=fa;
        ctx.drawImage(sprite, fcol*FW,frow*FH,FW,FH, imgCx-imgW/2,imgCy-imgH/2,imgW,imgH);
        ctx.globalAlpha=1;
        // difuminado de los bordes inferior y laterales de la mujer: se borran con un degradado
        // para que se fundan con el fondo blanco (sin corte brusco con la web / secciones).
        var ix0=imgCx-imgW/2;                         // borde izquierdo real de la imagen
        var yb=imgCy+imgH/2;                          // borde inferior de la imagen
        var bandB=imgH*0.18, bandL=imgW*0.42, bandX=W*0.12; // anchos de difuminado (izda mucho mayor)
        ctx.globalCompositeOperation="destination-out";
        var gB=ctx.createLinearGradient(0,yb-bandB,0,yb);
        gB.addColorStop(0,"rgba(0,0,0,0)"); gB.addColorStop(1,"rgba(0,0,0,1)");
        ctx.fillStyle=gB; ctx.fillRect(0,yb-bandB,W,bandB);
        // se desvanece desde el borde izquierdo de la imagen hacia la figura (funde el canto con el blanco)
        var gL=ctx.createLinearGradient(ix0,0,ix0+bandL,0);
        gL.addColorStop(0,"rgba(0,0,0,1)"); gL.addColorStop(1,"rgba(0,0,0,0)");
        ctx.fillStyle=gL; ctx.fillRect(ix0,0,bandL,H);
        var gR=ctx.createLinearGradient(W-bandX,0,W,0);
        gR.addColorStop(0,"rgba(0,0,0,0)"); gR.addColorStop(1,"rgba(0,0,0,1)");
        ctx.fillStyle=gR; ctx.fillRect(W-bandX,0,bandX,H);
        ctx.globalCompositeOperation="source-over";
      }
    }

    if(cellsReady && !scene2 && pp>=0.26){
      // ESCENA 1: persona → mapamundi 1 (derecha)
      var sin=Math.sin(angle1),cos=Math.cos(angle1);
      var wdx=-0.95, wdy=-0.30, pxx=0.30, pyy=-0.95;
      var WIND=R*1.35, LAT=R*0.75, SWAY=R*0.30, BOB=R*0.13;
      for(var i=0;i<N;i++){
        var pt=P[i], c=pt.cell, g=pt.glb;
        var t=easeInOut(clamp((m1-pt.delay)/0.40,0,1));
        var ix=imgCx+c.u*imgW, iy=imgCy+c.v*imgH;
        var xr=g.x*cos+g.z*sin, zr=-g.x*sin+g.z*cos, yr=g.y;
        var gx=cx+xr*R, gy=cy-yr*R, depth=(zr+1)/2;
        var it=1-t;
        var midx=(ix+gx)*0.5, midy=(iy+gy)*0.5;
        var cpx=midx + wdx*WIND*pt.wind + pxx*LAT*pt.lat;
        var cpy=midy + wdy*WIND*pt.wind + pyy*LAT*pt.lat;
        var X=it*it*ix + 2*it*t*cpx + t*t*gx;
        var Y=it*it*iy + 2*it*t*cpy + t*t*gy;
        var fade=it;
        var sway=Math.sin(t*Math.PI*pt.swayF + pt.phase)*SWAY*pt.swayA*fade;
        X+=pxx*sway; Y+=pyy*sway;
        Y+=Math.sin(t*Math.PI*2+pt.phase)*BOB*pt.bob*fade;
        var ct=clamp(t*1.25,0,1);
        var cr=(c.r+(11-c.r)*ct)|0, cg=(c.g+(14-c.g)*ct)|0, cb=(c.b+(18-c.b)*ct)|0;
        var side=lerp(imgPitch*1.05, lerp(2.4,4.0,depth)*0.55, t);
        var a=lerp(0.97, lerp(0.12,0.92,depth), t);
        if(a<=0.02||side<=0.3) continue;
        ctx.fillStyle="rgba("+cr+","+cg+","+cb+","+a+")";
        var hh=side*0.5; ctx.fillRect(X-hh,Y-hh,side,side);
      }
    }

    if(cellsReady && !scene2){
      // Marcadores amarillos que laten sobre el mapamundi formado (solo cara frontal).
      var mk = remap(pp,0.50,0.58) * (1 - remap(pp,0.61,0.64));
      if(mk>0){
        var ms=Math.sin(angle1), mc=Math.cos(angle1);
        var tnow=(typeof performance!=="undefined"?performance.now():Date.now())/1000;
        for(var k=0;k<MARKERS.length;k++){
          var mm=MARKERS[k];
          var mxr=mm.x*mc+mm.z*ms, mzr=-mm.x*ms+mm.z*mc;
          if(mzr<=0.05) continue;                       // oculta los de la cara trasera
          var mgx=cx+mxr*R, mgy=cy-mm.y*R, mdepth=(mzr+1)/2;
          var pulse=1+0.45*Math.sin(tnow*mm.speed + mm.phase);
          var rad=mm.size*R*(0.7+0.3*mdepth)*pulse;
          var al=mk*(0.55+0.45*mdepth);
          ctx.beginPath(); ctx.fillStyle="rgba(255,212,0,"+(al*0.22)+")";
          ctx.arc(mgx,mgy,rad*2.2,0,TWO_PI); ctx.fill();   // halo suave
          ctx.beginPath(); ctx.fillStyle="rgba(255,212,0,"+al+")";
          ctx.arc(mgx,mgy,rad,0,TWO_PI); ctx.fill();       // punto sólido
        }
      }
    }

    if(cellsReady && scene2){
      // ESCENA 2: el mapamundi 1 (derecha) se descompone y sus fragmentos RECONSTRUYEN EL VÍDEO 2
      // (columna izquierda). Origen con orientación CONGELADA en el relevo → son los mismos fragmentos.
      // Movimiento directo y progresivo; al posarse recuperan su color real y se funde el fotograma nítido.
      var aF=TWO_PI*(TURNS*easeInOut(remap(0.64,0.22,0.60)) + 0.8*0.64);
      var sA=Math.sin(aF), cA=Math.cos(aF);
      for(var i=0;i<N;i++){
        var pt=P[i], g=pt.glb, c2=pt.cell2;
        var t=easeInOut(clamp((m2-pt.delay)/0.40,0,1));
        var xr1=g.x*cA+g.z*sA, zr1=-g.x*sA+g.z*cA, depth=(zr1+1)/2;
        var sx=cx+xr1*R, sy=cy-g.y*R;                       // origen: fragmento del globo 1 (derecha)
        var dx2=img2Cx+c2.u*img2W, dy2=img2Cy+c2.v*img2H;   // destino: su píxel en el vídeo 2 (izquierda)
        var X=lerp(sx,dx2,t), Y=lerp(sy,dy2,t);             // desplazamiento directo y progresivo
        var cr=lerp(11,c2.r,t)|0, cg=lerp(14,c2.g,t)|0, cb=lerp(18,c2.b,t)|0; // negro → color real
        var side=lerp(lerp(2.4,4.0,depth)*0.55, img2Pitch*1.05, t);           // globo → píxel
        var a=lerp(lerp(0.12,0.92,depth), 0.97, t);
        if(a<=0.02||side<=0.3) continue;
        ctx.fillStyle="rgba("+cr+","+cg+","+cb+","+a+")";
        var hh=side*0.5; ctx.fillRect(X-hh,Y-hh,side,side);
      }
      // fundido del fotograma real del vídeo 2 por encima, para una imagen nítida al final
      if(sprite2Ready){
        var fa2=remap(pp,0.82,0.87);
        if(fa2>0){
          var pf=clamp(Math.round(remap(pp,0.87,1.0)*(V2.frames-1)),0,V2.frames-1); // reproduce el clip
          var f2=pf, c2col=f2%V2.cols, c2row=(f2/V2.cols)|0;
          ctx.globalAlpha=fa2;
          ctx.drawImage(sprite2, c2col*V2.fw,c2row*V2.fh,V2.fw,V2.fh, img2Cx-img2W/2,img2Cy-img2H/2,img2W,img2H);
          ctx.globalAlpha=1;
          // difuminado de los bordes (derecho hacia el copy, e inferior) fundiéndolos con el blanco.
          // Escalado por fa2 para no recortar los fragmentos mientras vuelan.
          var ix2=img2Cx-img2W/2, ix2r=img2Cx+img2W/2, yb2=img2Cy+img2H/2;
          var b2B=img2H*0.16, b2R=img2W*0.07, b2L=img2W*0.07;
          ctx.globalCompositeOperation="destination-out";
          var g2B=ctx.createLinearGradient(0,yb2-b2B,0,yb2);
          g2B.addColorStop(0,"rgba(0,0,0,0)"); g2B.addColorStop(1,"rgba(0,0,0,"+fa2+")");
          ctx.fillStyle=g2B; ctx.fillRect(0,yb2-b2B,W,b2B);
          var g2R=ctx.createLinearGradient(ix2r-b2R,0,ix2r,0);
          g2R.addColorStop(0,"rgba(0,0,0,0)"); g2R.addColorStop(1,"rgba(0,0,0,"+fa2+")");
          ctx.fillStyle=g2R; ctx.fillRect(ix2r-b2R,0,b2R,H);
          var g2L=ctx.createLinearGradient(ix2,0,ix2+b2L,0);
          g2L.addColorStop(0,"rgba(0,0,0,"+fa2+")"); g2L.addColorStop(1,"rgba(0,0,0,0)");
          ctx.fillStyle=g2L; ctx.fillRect(ix2,0,b2L,H);
          ctx.globalCompositeOperation="source-over";
        }
      }
    }
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);
})();
